+// Function to join namespaces
+std::string joinNamespaces(const std::vector<std::string> &namespaces,
+                           const std::string &delimiter = "::") {
+    std::ostringstream joined;
+    for (size_t i = 0; i < namespaces.size(); ++i) {
+        joined << namespaces[i];
+        if (i != namespaces.size() - 1) {
+            joined << delimiter;
+        }
+    }
+    return joined.str();
+}
